//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
  // 팝업으로 열린 경우 자산번호 세팅
  if (typeof scwin.valueObject != "undefined" && scwin.valueObject != null) {
    let parent_slipNo = scwin.valueObject.slipNo;
    if (parent_slipNo != null) {
      dma_search.set("slipNo", parent_slipNo);
      $c.gus.cf_HideObject($p, [buttonArea]);
      $c.gus.cf_HideObject($p, [searchArea]);
      let e = await $c.sbm.execute($p, sbm_search);
      scwin.sbm_search_submitdone(e);
      $c.gus.cfDisableObjects($p, [btn_Search]);
      return;
    }
  }
  ed_runDtFrom.setValue(scwin.strFromDate);
  ed_runDtTo.setValue(scwin.strToDay);
  ed_slipDt.setValue(scwin.strToDay);
  ed_userId.setValue(scwin.vUserId);
  ed_userNm.setValue(scwin.vUserNm);
  acb_acctCd.setSelectedIndex(0);
  ed_acctDeptCd.setValue(scwin.vAcctDeptCd);
  ed_acctDeptNm.setValue(scwin.vAcctDeptNm);
  if (scwin.vAcctDeptCd != "00009") {
    //재경팀은 전체 조회가능
    $c.gus.cfDisableObjects($p, [ed_userId, ed_userNm]);
    $c.gus.cfEnableObj($p, btn_userId, false);
  } else {
    $c.gus.cfEnableObjects($p, [ed_userId, ed_userNm]);
    $c.gus.cfEnableObj($p, btn_userId, true);
  }
  $c.gus.cfDisableObjects($p, [btn_Modify, btn_AddRow, btn_UndoRow, btn_CopyRow, btn_Pro, btn_Save, btn_Delete]);
  scwin.f_SeachVehclNo();
  scwin.f_SeachDeptCost();
};

//-------------------------------------------------------------------------
// 로그인 사용자 개인차량 등록체크
//-------------------------------------------------------------------------
scwin.f_SeachVehclNo = async function () {
  // SELECT 절
  let param1 = "VEHCL_NO   as COL1 " //차량번호
  + ",VEHCL_NM     as COL2 " //차량명
  + ",''           as COL3 " + ",''           as COL4 " + ",''           as COL5 " + ",''           as COL6 " + ",''           as COL7 " + ",''           as COL8 " + ",''           as COL9 " + ",''           as COL10 ";

  // 대상테이블
  let param2 = "TB_ZZ614";
  let param3 = "AND USE_YN = 1 AND APPRV_YN = 1 AND USER_ID = '" + scwin.vUserId + "'";
  let param4 = "VEHCL_NO";
  dma_perVehcl.set("param1", param1);
  dma_perVehcl.set("param2", param2);
  dma_perVehcl.set("param3", param3);
  dma_perVehcl.set("param4", param4);
  sbm_perVehcl.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
  let e = await $c.sbm.execute($p, sbm_perVehcl);
  scwin.sbm_perVehcl_submitdone(e);
};

//-------------------------------------------------------------------------
// 로그인 사용자부서  비용구분 확인
//-------------------------------------------------------------------------
scwin.f_SeachDeptCost = function () {
  // SELECT 절
  let param1 = "COST_CLS_CD  as COL1 " //비용구분
  + ",''           as COL2 " + ",''           as COL3 " + ",''           as COL4 " + ",''           as COL5 " + ",''           as COL6 " + ",''           as COL7 " + ",''           as COL8 " + ",''           as COL9 " + ",''           as COL10 ";

  // 대상테이블
  let param2 = "TB_CO001";
  let param3 = "AND ACCT_DEPT_CD = '" + scwin.vAcctDeptCd + "'";
  let param4 = "COST_CLS_CD";
  dma_deptCost.set("param1", param1);
  dma_deptCost.set("param2", param2);
  dma_deptCost.set("param3", param3);
  dma_deptCost.set("param4", param4);
  sbm_deptCost.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
  $c.sbm.execute($p, sbm_deptCost);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  let ret = await $c.gus.cfValidate($p, [ed_runDtFrom, ed_runDtTo]);
  if (!ret) {
    return true;
  }
  if (ed_runDtFrom.getValue() == "" || ed_runDtTo.getValue() == "") {
    await $c.win.alert($p, "운행일시는 필수 입력 항목입니다.");
    return;
  }

  //부서
  if (scwin.vAcctDeptCd != "00009") {
    if (ed_userId.getValue() == "") {
      await $c.win.alert($p, "사용자는 필수 입력 항목입니다.");
      ed_userId.focus();
      return;
    }
  }
  if (!$c.gus.cfIsAfterDate($p, ed_runDtFrom.getValue().trim(), ed_runDtTo.getValue().trim())) {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_039));
    ed_runDtFrom.focus();
    return false;
  }
  let e = await $c.sbm.execute($p, sbm_search);
  scwin.sbm_search_submitdone(e);
};

//-------------------------------------------------------------------------
// 저장시
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  //  필수입력사항 확인
  let ret = await $c.gus.cfValidate($p, [gr_master]);
  if (!ret) {
    return;
  }
  if (ds_master.getModifiedIndex().length === 0) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }

  // 저장전 원가/판관부서에 따른 계정체크
  for (let i = 0; i < ds_master.getRowCount(); i++) {
    let acctCd = ds_master.getCellData(i, "acctCd");
    let costClsCd = ds_master.getCellData(i, "costClsCd");

    /* 01 원가 , 02 판관비, 03 원가+판관비 */
    if (acctCd.substring(0, 1) == "4" && costClsCd == "02") {
      //원가
      await $c.win.alert($p, "판관비부서에 원가계정 선택은 불가합니다.");
      return;
    } else if (acctCd.substring(0, 1) == "5" && costClsCd == "01") {
      //판관비
      await $c.win.alert($p, "원가부서에 판관비계정 선택은 불가합니다.");
      return;
    }
  }
  if ((await $c.win.confirm($p, "저장하시겠습니까?")) == true) {
    $c.sbm.execute($p, sbm_save);
  }
};

//-------------------------------------------------------------------------
// 삭제시
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
  if (ds_master.getModifiedIndex().length === 0) {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_056, "데이타"));
    return;
  }
  let msg = "번째 데이타는 전표내역이 있어 삭제할 수 없습니다.";
  // 이미 발행된건 삭제하지 않는다.
  for (let i = 0; i < ds_master.getRowCount(); i++) {
    if (ds_master.getRowStatus(i) == "U" && ds_master.getCellData(i, "slipNo") != "") {
      await $c.win.alert($p, i + 1 + msg);
      return;
    }
  }
  if ((await $c.win.confirm($p, $c.data.getMessage($p, MSG_CM_CRM_008, "선택하신 데이타"))) == true) {
    for (let i = ds_master.getRowCount() - 1; i >= 0; i--) {
      if (ds_master.getCellData(i, "chk") == "T") {
        ds_master.deleteRow(i);
      }
    }
    $c.sbm.execute($p, sbm_save);
  }
};

//-------------------------------------------------------------------------
// 전표발행시
//-------------------------------------------------------------------------
scwin.f_Process = async function () {
  if (ds_master.getModifiedIndex().length === 0) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }

  //  필수입력사항 확인
  let ret = await $c.gus.cfValidate($p, [gr_master]);
  if (!ret) {
    return;
  }
  if (ed_slipDt.getValue() == "") {
    await $c.win.alert($p, "작성일자는 필수 입력 항목입니다.");
    return;
  }
  if (ed_summary.getValue() == "") {
    await $c.win.alert($p, "적요는 필수 입력 항목입니다.");
    return;
  }
  if ((await $c.win.confirm($p, "전표 발행하시겠습니까?")) == true) {
    await scwin.f_SlipCreate();
  }
};

