scwin.f_VatDeclarAcctDeptCd = async function (_acctDeptCd) {
  let param = "," + _acctDeptCd + "," + scwin.vCoCd + "," + scwin.vCoClsCd + "," + ed_slipDt.getValue().substring(0, 4);
  let check = "T";
  let popTemp = "ZZ";
  let vatDeclarAcctDeptCd = "";

  // 부가세신고부서에 값을넣고 명을 찾을 경우
  await udc_vatDeclarAcctDeptCd.cfCommonPopUpAsync(function (rtnList) {
    if (rtnList != null) {
      if (rtnList[0] == "N/A") {} else {
        vatDeclarAcctDeptCd = rtnList[2]; //부가세부서코드
      }
    }
  }, "", popTemp, check, null, null, null, null, param, null, null, null, null);
  return vatDeclarAcctDeptCd;
};

