scwin.f_Excel = async function () {
  if (ds_master.getRowCount() == 0) {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_WRN_002));
    return;
  }
  let colCount = 0;
  for (let i = 0; i < gr_master.getTotalCol(); i++) {
    if (gr_master.getColumnVisible(i) == true) {
      colCount++;
    }
  }
  let infoArr = [{
    rowIndex: 0,
    colIndex: 0,
    rowSpan: 1,
    colSpan: colCount,
    text: "개인차량유류비정산 내역",
    textAlign: "center",
    fontSize: 18,
    drawBorder: false,
    color: "black",
    backgroundColor: "white"
  }];
  const options = {
    fileName: '정산처리 내역.xlsx',
    sheetName: '정산처리 내역',
    startRowIndex: 2,
    startColumnIndex: 0,
    columnMove: true,
    columnMoveWithFooter: true,
    type: 1
  };
  gr_master.setFooterStyle("column44", "text-align", "right");
  $c.data.downloadGridViewExcel($p, gr_master, options, infoArr);
  gr_master.setFooterStyle("column44", "text-align", "center");
};

