scwin.gr_master_onheaderclick = function (headerId) {
  if (headerId == "header_chk") {
    let bCheck = gr_master.getHeaderValue(headerId);
    if (bCheck == "1") {
      for (let i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getCellData(i, "slipNo") == "") {
          ds_master.setCellData(i, "chk", "T");
        }
      }
    } else {
      for (let i = 0; i < ds_master.getRowCount(); i++) {
        ds_master.setCellData(i, "chk", "F");
      }
    }
  }
};
scwin.gr_master_oncellclick = async function (rowIndex, columnIndex, columnId) {
  if (columnId == "chk") {
    if (ds_master.getCellData(rowIndex, "slipNo") != "") {
      await $c.win.alert($p, "전표가 이미 발행 된 상태입니다.");
      ds_master.setCellData(rowIndex, "chk", "F");
    }
  }
  if (columnId == "slipNo" && rowIndex >= 0 && ds_master.getCellData(rowIndex, "slipNo") != "") {
    await $c.gus.cfShowSlipInfo($p, ds_master.getCellData(rowIndex, "slipNo"));
    return;
  }
  if (ds_master.getRowStatus(rowIndex) != "C") {
    //신규가 아닐경우
    gr_master.setColumnReadOnly("runDt", true); //운행일시
    gr_master.setColumnReadOnly("vehclNm", true); //차종
  } else {
    //신규
    gr_master.setColumnReadOnly("runDt", false);
    gr_master.setColumnReadOnly("vehclNm", false);
  }
  gr_master.setColumnReadOnly("userNm", true); // 본인 차량에 대해서만 가능

  if (ds_master.getCellData(rowIndex, "slipNo") == "") {
    scwin.f_ChgGridView("N");
    gr_master.setColumnReadOnly("dptWrkPlNm", false); //출발지
    gr_master.setColumnReadOnly("arvWrkPlNm", false); //도착지
    gr_master.setColumnReadOnly("fuelUpr", false); //유류비
    gr_master.setColumnReadOnly("runDtc", false); //운행거리
    gr_master.setColumnReadOnly("rmk", false); //상세내역
  } else {
    scwin.f_ChgGridView("Y");
    gr_master.setColumnReadOnly("dptWrkPlNm", true);
    gr_master.setColumnReadOnly("arvWrkPlNm", true);
    gr_master.setColumnReadOnly("fuelUpr", true);
    gr_master.setColumnReadOnly("runDtc", true);
    gr_master.setColumnReadOnly("rmk", true);
  }
};
scwin.gr_master_ontextimageclick = async function (rowIndex, columnIndex) {
  let colid = gr_master.getColumnID(columnIndex);
  if (colid == "userNm") {
    //사용자
    await scwin.f_openCommPopUpGrid(1, rowIndex, '', ds_master.getCellData(rowIndex, "userNm"), 'T', 'F');
  } else if (colid == "vehclNm") {
    //차종
    await scwin.f_openCommPopUpGrid(2, rowIndex, '', ds_master.getCellData(rowIndex, "vehclNm"), 'T', 'T');
  } else if (colid == "acctDeptNm") {
    //귀속부서
    await scwin.f_openCommPopUpGrid(3, rowIndex, '', ds_master.getCellData(rowIndex, "acctDeptNm"), 'T', 'F');
  } else if (colid == "adjmClntNm") {
    //정산처
    await scwin.f_openCommPopUpGrid(4, rowIndex, '', ds_master.getCellData(rowIndex, "adjmClntNm"), 'T', 'F');
  } else if (colid == "acctNm") {
    //계정코드
    await scwin.f_openCommPopUpGrid(5, rowIndex, '', ds_master.getCellData(rowIndex, "acctNm"), 'T', 'F');
  }
};
scwin.gr_master_focusOut = async function (row, colid, columnIndex, value) {
  let olddata = scwin.oldData;
  let newdata = value;
  if (colid == "vehclNm") {
    if (newdata != olddata) {
      await scwin.f_openCommPopUpGrid(2, row, '', ds_master.getCellData(row, "vehclNm"), 'T', 'T');
    }
  } else if (colid == "acctDeptNm") {
    if (newdata != olddata) {
      await scwin.f_openCommPopUpGrid(3, row, '', ds_master.getCellData(row, "acctDeptNm"), 'T', 'F');
    }
  } else if (colid == "adjmClntNm") {
    if (newdata != olddata) {
      await scwin.f_openCommPopUpGrid(4, row, '', ds_master.getCellData(row, "adjmClntNm"), 'T', 'F');
    }
  } else if (colid == "acctNm") {
    if (newdata != olddata) {
      await scwin.f_openCommPopUpGrid(5, row, '', ds_master.getCellData(row, "acctNm"), 'T', 'F');
    }
  }
};
scwin.gr_master_onbeforeedit = function (rowIndex, columnIndex, value) {
  scwin.oldData = value;
};
scwin.gr_master_onafteredit = function (rowIndex, columnIndex, value, info) {
  let colId = gr_master.getColumnID(columnIndex);
  if (info.type == 'mousedown') {
    return false;
  } else {
    scwin.gr_master_focusOut(rowIndex, colId, columnIndex, value);
  }
};
scwin.btn_Modify_onclick = function (e) {
  scwin.f_Modify();
};
scwin.gr_master_onviewchange = async function (info) {
  let row = info.rowIndex;
  let colid = info.colId;
  if (colid == "runDt") {
    //운행일시
    if (ds_master.getCellData(row, "userId") != "" && ds_master.getCellData(row, "runDt") != "") {
      if (ds_perVehcl.getRowCount() == 1) {
        //등록된 개인차량이 1건일경우
        await scwin.f_openCommPopUpGrid(2, row, scwin.vPerVehclNo, '', 'T', 'F');
      } else {
        await scwin.f_openCommPopUpGrid(2, row, '', ds_master.getCellData(row, "vehclNm"), 'T', 'F');
      }
    }
  } else if (colid == "runDtc" || colid == "fuelUpr") {
    //운행거리, 유류비
    // 지원금액 산식 = 운행거리 / 적용연비 x 유류비 (row별 10의자리 반올림)
    let appEffcncy = ds_master.getCellData(row, "appEffcncy");
    let supAmt = Math.round(ds_master.getCellData(row, "runDtc") / appEffcncy * ds_master.getCellData(row, "fuelUpr"));
    supAmt = Math.round(supAmt / 100) * 100;
    ds_master.setCellData(row, "supAmt", supAmt);
  }
};
scwin.runDt_displayFormatFunc = function (calendarValueType) {
  for (let i = 0; i < ds_master.getRowCount(); i++) {
    let date = ds_master.getCellData(i, "runDt");
    if (date.length < 5) {
      return date + "/ " + " /";
    } else if (date.length < 7) {
      return date.substring(0, 4) + "/" + date.substring(4, 6) + "/ ";
    } else {
      return date.substring(0, 4) + "/" + date.substring(4, 6) + "/" + date.substring(6, 8);
    }
  }
};
scwin.runDt_displayFormatter = function (data) {
  if (data.length < 5) {
    return data + "/ " + " /";
  } else if (data.length < 7) {
    return data.substring(0, 4) + "/" + data.substring(4, 6) + "/ ";
  } else {
    return data.substring(0, 4) + "/" + data.substring(4, 6) + "/" + data.substring(6, 8);
  }
};
